class Solution {
    public int kIncreasing(int[] arr, int k) {
        int n = arr.length;
        int count = 0;
        for (int i = 0; i < k; i++) {
            int prev = arr[i];
            for (int j = i + k; j < n; j += k) {
                if (arr[j] < prev) {
                    count++;
                } else {
                    prev = arr[j];
                }
            }
        }
        return count;
    }
}

